'use client'

import { useState, useEffect, useCallback } from 'react'
import { useParams, useRouter } from 'next/navigation'
import type { Order, OrderStatus } from '@food-app/shared'
import { useAuth } from '@/context/AuthContext'
import { Navbar } from '@/components/layout/Navbar'
import { Badge } from '@/components/ui/Badge'
import { Button } from '@/components/ui/Button'
import { Spinner } from '@/components/ui/Spinner'
import { formatPrice, formatDate } from '@/lib/utils'
import { cn } from '@/lib/utils'

const STEPS: { status: OrderStatus; label: string; emoji: string }[] = [
  { status: 'placed', label: 'Order Placed', emoji: '✅' },
  { status: 'preparing', label: 'Preparing', emoji: '👨‍🍳' },
  { status: 'out_for_delivery', label: 'Out for Delivery', emoji: '🛵' },
  { status: 'delivered', label: 'Delivered', emoji: '🎉' },
]

const STATUS_VARIANTS: Record<string, 'default' | 'success' | 'warning' | 'error' | 'info'> = {
  placed: 'info',
  preparing: 'warning',
  out_for_delivery: 'info',
  delivered: 'success',
  cancelled: 'error',
}

function getStepIndex(status: OrderStatus) {
  return STEPS.findIndex((s) => s.status === status)
}

export default function OrderTrackingPage() {
  const { id } = useParams<{ id: string }>()
  const { isAuthenticated, isLoading, token } = useAuth()
  const router = useRouter()
  const [order, setOrder] = useState<Order | null>(null)
  const [loading, setLoading] = useState(true)

  const fetchOrder = useCallback(async () => {
    const res = await fetch(`/api/orders/${id}`, {
      headers: { Authorization: `Bearer ${token}` },
    })
    const data = await res.json()
    if (data.order) setOrder(data.order)
  }, [id, token])

  useEffect(() => {
    if (isLoading) return
    if (!isAuthenticated) { router.replace('/login'); return }
    fetchOrder().finally(() => setLoading(false))
  }, [isAuthenticated, isLoading, fetchOrder, router])

  // Poll every 5 seconds while not delivered
  useEffect(() => {
    if (!order || order.status === 'delivered' || order.status === 'cancelled') return
    const interval = setInterval(fetchOrder, 5000)
    return () => clearInterval(interval)
  }, [order, fetchOrder])

  if (isLoading || loading) {
    return (
      <>
        <Navbar />
        <div className="flex justify-center py-20">
          <Spinner className="h-8 w-8 text-orange-500" />
        </div>
      </>
    )
  }

  if (!order) {
    return (
      <>
        <Navbar />
        <div className="py-20 text-center text-gray-500">Order not found.</div>
      </>
    )
  }

  const stepIndex = getStepIndex(order.status as OrderStatus)

  return (
    <>
      <Navbar />
      <main className="mx-auto max-w-2xl px-4 py-8">
        <div className="mb-6 flex items-center justify-between">
          <div>
            <h1 className="text-2xl font-bold text-gray-900">Order Tracking</h1>
            <p className="text-sm text-gray-500">Order #{order.id} · {order.restaurantName}</p>
          </div>
          <Badge variant={STATUS_VARIANTS[order.status]}>
            {STEPS.find((s) => s.status === order.status)?.label ?? order.status}
          </Badge>
        </div>

        {/* Progress stepper */}
        <div className="mb-8 rounded-xl border border-gray-200 bg-white p-6">
          <div className="flex justify-between">
            {STEPS.map((step, i) => {
              const done = i <= stepIndex
              const active = i === stepIndex
              return (
                <div key={step.status} className="flex flex-1 flex-col items-center">
                  <div
                    className={cn(
                      'flex h-10 w-10 items-center justify-center rounded-full text-xl transition',
                      done ? 'bg-orange-100' : 'bg-gray-100',
                      active && 'ring-2 ring-orange-500 ring-offset-2'
                    )}
                  >
                    {step.emoji}
                  </div>
                  <p className={cn('mt-2 text-center text-xs font-medium', done ? 'text-orange-600' : 'text-gray-400')}>
                    {step.label}
                  </p>
                  {/* connector line */}
                  {i < STEPS.length - 1 && (
                    <div className="absolute" />
                  )}
                </div>
              )
            })}
          </div>
          {/* connector */}
          <div className="relative mt-[-2.5rem] mb-5 flex justify-between px-5">
            {STEPS.slice(0, -1).map((_, i) => (
              <div
                key={i}
                className={cn('h-0.5 flex-1', i < stepIndex ? 'bg-orange-400' : 'bg-gray-200')}
              />
            ))}
          </div>

          {order.status !== 'delivered' && (
            <p className="mt-4 text-center text-sm text-gray-500">
              Estimated delivery: <span className="font-medium">{formatDate(order.estimatedDelivery)}</span>
            </p>
          )}
          {order.status === 'delivered' && (
            <p className="mt-4 text-center text-sm text-green-600 font-medium">
              🎉 Your order was delivered!
            </p>
          )}
        </div>

        {/* Items */}
        <div className="rounded-xl border border-gray-200 bg-white p-5">
          <h2 className="mb-3 font-semibold text-gray-900">Items</h2>
          <div className="flex flex-col gap-2 text-sm text-gray-600">
            {order.items.map((item) => (
              <div key={item.menuItemId} className="flex justify-between">
                <span>{item.name} × {item.quantity}</span>
                <span>{formatPrice(item.price * item.quantity)}</span>
              </div>
            ))}
            <div className="my-2 border-t border-gray-200" />
            <div className="flex justify-between"><span>Subtotal</span><span>{formatPrice(order.subtotal)}</span></div>
            <div className="flex justify-between"><span>Delivery</span><span>{formatPrice(order.deliveryFee)}</span></div>
            <div className="flex justify-between font-semibold text-gray-900">
              <span>Total</span><span>{formatPrice(order.total)}</span>
            </div>
          </div>
        </div>

        <p className="mt-3 text-xs text-gray-400 text-center">Placed {formatDate(order.placedAt)}</p>

        <div className="mt-6 flex justify-center gap-3">
          <Button variant="secondary" onClick={() => router.push('/orders')}>All Orders</Button>
          <Button onClick={() => router.push('/restaurants')}>Order Again</Button>
        </div>
      </main>
    </>
  )
}
